  if(Boolean(source.LastName)){
    value = source.LastName.split('-')[0].trim();
    
    // Sorteer prefixes van lang naar kort (zodat "van de" voor "van" wordt gecheckt)
    const sortedPrefixes = commonPrefixes.sort((a, b) => b.length - a.length);
    
    for(let prefix of sortedPrefixes){
      const prefixWithSpace = prefix + ' ';
      if(value.toLowerCase().startsWith(prefixWithSpace.toLowerCase())){
        value = value.substring(prefixWithSpace.length).trim();
